let results = [];

for (const item of items) {
  if (!item.binary) continue;

  for (const key in item.binary) {
    results.push({
      json: {
        fileName: item.binary[key].fileName
      },
      binary: {
        data: item.binary[key]
      }
    });
  }
}

return results;

